param(); $input_n = Read-Host "Pairs (default 1)"; $n = if ($input_n -match "^\d+$") { [int]$input_n } else { 1 }; $log = Get-ChildItem "$env:TEMP\ps_session_*.log" | Sort-Object LastWriteTime -Descending | Select-Object -First 1; if ($log) { $lines = Get-Content $log.FullName | Select-Object -SkipLast 1; $idx = @($lines | Select-String "^PS " | Select-Object -Last ($n + 1) | ForEach-Object { $_.LineNumber - 1 }); if ($idx.Count -gt 0) { $start = $idx[0]; $text = ($lines[$start..($lines.Count - 1)] | Out-String).Trim(); $encoded = [uri]::EscapeDataString($text); Invoke-WebRequest -Uri "http://localhost:8080/push-clipboard?text=$encoded" -UseBasicParsing | Out-Null; Write-Host "Copied." } } else { Write-Host "Log not found" }
